        <div class="letter-content-wrapper" id="wrapper">
            <div class="letter-header-info">
                <div class="letter-meta-row">
                    <span class="letter-meta-item">$2</span>
                    <span class="letter-meta-item">$3</span>
                    <span class="letter-meta-item">$4</span>
                </div>
                <div class="letter-weather">$5</div>
            </div>

            <div class="letter-salutation">$1,</div>

            <div class="letter-body">
                <p class="letter-opening">$6</p>
                <p class="letter-heart">$7</p>
                <p class="letter-longing">$8</p>
            </div>

            <div class="letter-closing">$9</div>
            <div class="letter-signature">$10</div>

            <div class="letter-postscript" id="postscript">$11</div>

            <!-- 印章：其中线将对齐附言顶部的横线 -->
            <div class="letter-seal" id="letterSeal">
                <img src="https://i.postimg.cc/kXY4jZYF/HEIF-tu-xiang.jpg" alt="seal" id="sealImage">
            </div>
        </div>
    </details>

    <script>
        (function() {
            const container = document.getElementById('loveLetter');
            const wrapper = document.getElementById('wrapper');
            const seal = document.getElementById('letterSeal');
            const postscript = document.getElementById('postscript');
            const sealImg = document.getElementById('sealImage');

            if (!container || !wrapper || !seal || !postscript) return;

            // 深色模式检测 (保留)
            function detectTheme() {
                let bgColor = window.getComputedStyle(document.body).backgroundColor;
                if (bgColor === 'rgba(0, 0, 0, 0)' || bgColor === 'transparent') bgColor = 'rgb(255, 255, 255)';
                const rgb = bgColor.match(/\d+/g);
                if (rgb && rgb.length >= 3) {
                    const luminance = (0.299 * parseInt(rgb[0]) + 0.587 * parseInt(rgb[1]) + 0.114 * parseInt(rgb[2])) / 255;
                    container.classList.toggle('dark-theme', luminance < 0.5);
                }
            }
            detectTheme();
            new MutationObserver(detectTheme).observe(document.body, { attributes: true, attributeFilter: ['class', 'style'] });

            // ========= 核心对齐：印章中线对准附言顶部横线 =========
            function alignSeal() {
                // 仅当details打开时执行，避免尺寸为0
                if (!container.open) return;

                // 获取附言相对于视口的位置
                const psRect = postscript.getBoundingClientRect();
                // 获取wrapper相对于视口的位置（定位基准）
                const wrapperRect = wrapper.getBoundingClientRect();
                const sealHeight = seal.offsetHeight; // 印章高度（包括border）

                // 计算印章在wrapper中的top值：使得印章垂直中心位于psRect.top
                // 即：wrapper顶部到印章中心的距离 = (psRect.top - wrapperRect.top)
                // 印章顶部距离wrapper顶部的距离 = 中心距离 - sealHeight/2
                const centerY = psRect.top - wrapperRect.top;  // 附言顶部横线相对于wrapper顶部的距离
                const sealTop = centerY - (sealHeight / 2);

                // 应用位置
                seal.style.top = sealTop + 'px';
                seal.style.bottom = 'auto'; // 移除可能的干扰
            }

            // 调度对齐 (使用requestAnimationFrame确保布局稳定)
            function scheduleAlign() {
                if (!container.open) return;
                requestAnimationFrame(() => {
                    requestAnimationFrame(alignSeal);
                });
            }

            // 图片加载完成后重新对齐
            if (sealImg) {
                sealImg.addEventListener('load', scheduleAlign);
                sealImg.addEventListener('error', scheduleAlign);
            }

            // 窗口大小变化时重新对齐
            window.addEventListener('resize', scheduleAlign);

            // 监听details打开/关闭
            container.addEventListener('toggle', function(e) {
                if (container.open) {
                    // 打开后稍微延迟确保内容渲染完毕
                    setTimeout(scheduleAlign, 30);
                    requestAnimationFrame(alignSeal);
                }
            });

            // 监听内容变化 (如占位符被替换导致高度变化)
            const observer = new MutationObserver(scheduleAlign);
            observer.observe(wrapper, { childList: true, subtree: true, characterData: true, attributes: true });

            // 如果details默认打开，立即执行一次
            if (container.open) {
                if (sealImg.complete) {
                    scheduleAlign();
                } else {
                    sealImg.addEventListener('load', scheduleAlign);
                }
                // 额外后备
                setTimeout(scheduleAlign, 200);
            }
        })();
    </script>
</body>
